import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { ROLE_DASHBOARDS } from '../utils/constants';

const useAuthStore = create(
  persist(
    (set, get) => ({
      user: null,
      role: null,
      accessToken: null,
      refreshToken: null,
      isAuthenticated: false,

      setAuth: ({ user, role, access, refresh }) => {
        localStorage.setItem('access_token', access);
        localStorage.setItem('refresh_token', refresh);
        set({ user, role, accessToken: access, refreshToken: refresh, isAuthenticated: true });
      },

      setUser: (user) => set({ user }),

      logout: () => {
        localStorage.removeItem('access_token');
        localStorage.removeItem('refresh_token');
        set({ user: null, role: null, accessToken: null, refreshToken: null, isAuthenticated: false });
      },

      getDashboard: () => {
        const { role } = get();
        return ROLE_DASHBOARDS[role] || '/login';
      },
    }),
    {
      name: 'auth-storage',
      partialize: (state) => ({
        user: state.user,
        role: state.role,
        accessToken: state.accessToken,
        refreshToken: state.refreshToken,
        isAuthenticated: state.isAuthenticated,
      }),
    }
  )
);

export default useAuthStore;

export const formatDate = (dateStr, opts = {}) => {
  if (!dateStr) return '—';
  try {
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      ...opts,
    });
  } catch {
    return dateStr;
  }
};

export const formatDateTime = (dateStr) => {
  if (!dateStr) return '—';
  try {
    const d = new Date(dateStr);
    return d.toLocaleString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  } catch {
    return dateStr;
  }
};

export const formatRelative = (dateStr) => {
  if (!dateStr) return '—';
  try {
    const d = new Date(dateStr);
    const now = new Date();
    const diff = now - d;
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d ago`;
    return formatDate(dateStr);
  } catch {
    return dateStr;
  }
};

export const isExpired = (dateStr) => {
  if (!dateStr) return false;
  return new Date(dateStr) < new Date();
};

import { ROLE_DASHBOARDS } from './constants';

export const getRoleRedirect = (role) => {
  return ROLE_DASHBOARDS[role] || '/login';
};

export const decodeJwt = (token) => {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch {
    return null;
  }
};

export const isTokenExpired = (token) => {
  const decoded = decodeJwt(token);
  if (!decoded) return true;
  return decoded.exp * 1000 < Date.now();
};

export const getTokenRole = (token) => {
  const decoded = decodeJwt(token);
  return decoded?.role || null;
};

export const flattenClaims = (credentialSubject) => {
  if (!credentialSubject) return [];
  return Object.entries(credentialSubject)
    .filter(([key]) => key !== 'id')
    .map(([key, value]) => ({
      key,
      label: key
        .replace(/_/g, ' ')
        .replace(/([A-Z])/g, ' $1')
        .trim()
        .replace(/^\w/, (c) => c.toUpperCase()),
      value: typeof value === 'object' ? JSON.stringify(value) : String(value),
    }));
};

export const formatClaimValue = (value) => {
  if (value === null || value === undefined) return '—';
  if (typeof value === 'boolean') return value ? 'Yes' : 'No';
  if (typeof value === 'object') return JSON.stringify(value, null, 2);
  return String(value);
};

export const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB

export const ALLOWED_DOCUMENT_TYPES = [
  'application/pdf',
  'image/jpeg',
  'image/jpg',
  'image/png',
];

export const ALLOWED_CSV_TYPES = ['text/csv', 'application/vnd.ms-excel'];

export const validateFile = (file, allowedTypes = ALLOWED_DOCUMENT_TYPES, maxSize = MAX_FILE_SIZE) => {
  if (!allowedTypes.includes(file.type)) {
    return `File type not allowed. Accepted: ${allowedTypes.join(', ')}`;
  }
  if (file.size > maxSize) {
    return `File too large. Max size: ${(maxSize / 1024 / 1024).toFixed(0)}MB`;
  }
  return null;
};

export const formatFileSize = (bytes) => {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
};

import { createContext, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import * as authApi from '../api/auth';
import { getRoleRedirect } from '../utils/roleRedirect';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const { setAuth, logout: storeLogout, user, isAuthenticated, role } = useAuthStore();
  const navigate = useNavigate();

  const login = async (credentials) => {
    const res = await authApi.login(credentials);
    const { access, refresh, user: userData, role: userRole } = res.data;
    setAuth({ user: userData, role: userRole, access, refresh });
    toast.success('Logged in successfully');
    navigate(getRoleRedirect(userRole));
    return res.data;
  };

  const logout = async () => {
    try { await authApi.logout(); } catch { /* ignore */ }
    storeLogout();
    navigate('/login');
    toast.success('Logged out');
  };

  const refreshUser = async () => {
    try {
      const res = await authApi.getMe();
      useAuthStore.getState().setUser(res.data);
    } catch { /* ignore */ }
  };

  useEffect(() => {
    if (isAuthenticated) refreshUser();
  }, [isAuthenticated]);

  return (
    <AuthContext.Provider value={{ user, role, isAuthenticated, login, logout, refreshUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};

export default AuthContext;

import { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext(null);

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(() => localStorage.getItem('theme') || 'light');

  useEffect(() => {
    const root = document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggle = () => setTheme((t) => (t === 'light' ? 'dark' : 'light'));

  return (
    <ThemeContext.Provider value={{ theme, toggle, isDark: theme === 'dark' }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used inside ThemeProvider');
  return ctx;
};

