import { useState } from 'react';
import { useParams } from 'react-router-dom';
import { QrCode, Link as LinkIcon, Upload, Hash, CheckCircle, XCircle, AlertCircle } from 'lucide-react';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import { verifyPublic, verifyByToken } from '../../api/verifier';
import { formatDate } from '../../utils/formatDate';
import { flattenClaims } from '../../utils/claimsUtils';
import toast from 'react-hot-toast';

const METHODS = [
  { id: 'link', label: 'Share Link', icon: LinkIcon },
  { id: 'id', label: 'Credential ID', icon: Hash },
  { id: 'file', label: 'Upload File', icon: Upload },
];

function CheckRow({ label, passed }) {
