export default function VerifyPublicPage() {
  const { token: urlToken } = useParams();
  const [method, setMethod] = useState('link');
  const [input, setInput] = useState(urlToken || '');
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleVerify = async () => {
    setLoading(true);
    setResult(null);
    setError(null);
    try {
      let res;
      if (method === 'link' || method === 'id') {
        const token = input.trim().split('/').pop();
        res = await verifyPublic({ token, credential_id: method === 'id' ? input.trim() : undefined });
      } else if (method === 'file') {
        if (!file) { toast.error('Please select a file'); setLoading(false); return; }
        const text = await file.text();
        const data = JSON.parse(text);
        res = await verifyPublic({ credential_data: data });
      }
      setResult(res.data);
    } catch (err) {
      setError(err.response?.data?.detail || err.response?.data?.error || 'Verification failed. Please check your input.');
    } finally {
      setLoading(false);
    }
  };

  const isValid = result?.is_valid || result?.valid;
  const checks = result?.checks || {};
  const credential = result?.credential || result?.credential_data || {};
  const subject = credential?.credentialSubject || {};
  const claims = flattenClaims(subject);

  return (
    <div className="py-16 px-4">
      <div className="mx-auto max-w-2xl">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-bold text-foreground mb-3">Verify a Credential</h1>
          <p className="text-muted-foreground">No account required. Instantly verify any digital credential.</p>
        </div>

        {/* Method tabs */}
        <div className="flex gap-2 mb-6 rounded-xl bg-muted p-1">
          {METHODS.map((m) => (
            <button
              key={m.id}
              onClick={() => { setMethod(m.id); setResult(null); setError(null); }}
              className={`flex flex-1 items-center justify-center gap-2 rounded-lg py-2 text-sm font-medium transition-colors ${
                method === m.id ? 'bg-card shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <m.icon className="h-4 w-4" />
              <span className="hidden sm:block">{m.label}</span>
            </button>
          ))}
        </div>

        <div className="rounded-2xl border border-border bg-card p-6 mb-6">
          {method === 'link' && (
            <Input
              label="Paste Share Link or Token"
              placeholder="https://... or share token"
              value={input}
              onChange={(e) => setInput(e.target.value)}
            />
          )}
          {method === 'id' && (
            <Input
              label="Credential ID"
              placeholder="Enter credential UUID"
              value={input}
              onChange={(e) => setInput(e.target.value)}
            />
          )}
          {method === 'file' && (
            <div>
              <label className="mb-1.5 block text-sm font-medium text-foreground">Upload Credential File (JSON)</label>
              <input
                type="file"
                accept=".json"
                onChange={(e) => setFile(e.target.files[0])}
                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              />
              {file && <p className="mt-1 text-xs text-muted-foreground">{file.name}</p>}
            </div>
          )}
          <Button
            className="mt-4 w-full"
            onClick={handleVerify}
            loading={loading}
            disabled={method !== 'file' ? !input.trim() : !file}
          >
            Verify Credential
          </Button>
        </div>

        {/* Error */}
        {error && (
          <div className="rounded-xl border border-destructive/30 bg-destructive/10 p-4 mb-6">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-5 w-5 text-destructive shrink-0" />
              <p className="text-sm text-destructive">{error}</p>
            </div>
          </div>
        )}

        {/* Result */}
        {result && (
          <div className="rounded-2xl border border-border bg-card overflow-hidden">
            <div className={`px-6 py-5 ${isValid ? 'bg-green-50 dark:bg-green-900/20' : 'bg-red-50 dark:bg-red-900/20'}`}>
              <div className="flex items-center gap-3">
                {isValid
                  ? <CheckCircle className="h-8 w-8 text-green-600 dark:text-green-400" />
                  : <XCircle className="h-8 w-8 text-red-600 dark:text-red-400" />}
                <div>
                  <h2 className={`text-xl font-bold ${isValid ? 'text-green-700 dark:text-green-400' : 'text-red-700 dark:text-red-400'}`}>
                    {isValid ? 'Credential Verified' : 'Verification Failed'}
                  </h2>
                  {!isValid && result?.reason && (
                    <p className="text-sm text-red-600 dark:text-red-400">{result.reason}</p>
                  )}
                </div>
              </div>
            </div>

            <div className="p-6 space-y-6">
              {/* Verification checks */}
              {Object.keys(checks).length > 0 && (
                <div>
                  <h3 className="text-sm font-semibold text-foreground mb-3">Verification Checks</h3>
                  <div className="rounded-lg border border-border divide-y divide-border overflow-hidden">
                    {checks.signature !== undefined && <div className="px-4 py-0"><CheckRow label="Signature" passed={checks.signature} /></div>}
                    {checks.expiry !== undefined && <div className="px-4 py-0"><CheckRow label="Expiry" passed={checks.expiry} /></div>}
                    {checks.revocation !== undefined && <div className="px-4 py-0"><CheckRow label="Revocation" passed={checks.revocation} /></div>}
                    {checks.issuer_trust !== undefined && <div className="px-4 py-0"><CheckRow label="Issuer Trust" passed={checks.issuer_trust} /></div>}
                  </div>
                </div>
              )}

              {/* Credential info */}
              {credential && Object.keys(credential).length > 0 && (
                <div>
                  <h3 className="text-sm font-semibold text-foreground mb-3">Credential Details</h3>
                  <dl className="space-y-2">
                    {result?.issuer_name && (
                      <div className="flex justify-between text-sm">
                        <dt className="text-muted-foreground">Issuer</dt>
                        <dd className="font-medium text-foreground">{result.issuer_name}</dd>
                      </div>
                    )}
                    {result?.credential_type && (
                      <div className="flex justify-between text-sm">
                        <dt className="text-muted-foreground">Type</dt>
                        <dd className="font-medium text-foreground">{result.credential_type}</dd>
                      </div>
                    )}
                    {credential?.issuanceDate && (
                      <div className="flex justify-between text-sm">
                        <dt className="text-muted-foreground">Issued</dt>
                        <dd className="font-medium text-foreground">{formatDate(credential.issuanceDate)}</dd>
                      </div>
                    )}
                    {credential?.expirationDate && (
                      <div className="flex justify-between text-sm">
                        <dt className="text-muted-foreground">Expires</dt>
                        <dd className="font-medium text-foreground">{formatDate(credential.expirationDate)}</dd>
                      </div>
                    )}
                  </dl>
                </div>
              )}

              {/* Claims */}
              {claims.length > 0 && (
                <div>
                  <h3 className="text-sm font-semibold text-foreground mb-3">Shared Claims</h3>
                  <dl className="space-y-2">
                    {claims.map((c) => (
                      <div key={c.key} className="flex justify-between text-sm">
                        <dt className="text-muted-foreground">{c.label}</dt>
                        <dd className="font-medium text-foreground max-w-xs text-right">{c.value}</dd>
                      </div>
                    ))}
                  </dl>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

