import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { nidInitiate, nidVerifyOtp, registerWebHolder } from '../../api/auth';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const STEPS = ['Identity', 'OTP Verification', 'Account Setup'];

export default function HolderRegisterPage() {
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [fin, setFin] = useState('');
  const [sessionId, setSessionId] = useState('');
  const [otp, setOtp] = useState('');
  const [nidData, setNidData] = useState(null);
  const { login } = useAuth();
  const navigate = useNavigate();

  const { register, handleSubmit, formState: { errors }, watch } = useForm();

  // Step 0: Enter National ID (FIN)
  const handleFin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await nidInitiate({ fin });
      setSessionId(res.data.session_id || res.data.verification_id || '');
      toast.success('OTP sent to your registered phone number');
      setStep(1);
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to initiate verification');
    } finally {
      setLoading(false);
    }
  };

  // Step 1: Verify OTP
  const handleOtp = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await nidVerifyOtp({ fin, otp, session_id: sessionId });
      setNidData(res.data);
      toast.success('Identity verified successfully');
      setStep(2);
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Invalid OTP');
    } finally {
      setLoading(false);
    }
  };

  // Step 2: Create account
  const onSubmit = async (data) => {
    setLoading(true);
    try {
      await registerWebHolder({
        fin,
        session_id: sessionId,
        email: data.email,
        password: data.password,
        first_name: nidData?.first_name || data.first_name,
        last_name: nidData?.last_name || data.last_name,
      });
      toast.success('Account created! Signing you in...');
      await login({ email: data.email, password: data.password });
    } catch (err) {
      toast.error(err.response?.data?.detail || Object.values(err.response?.data || {})[0]?.[0] || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {/* Step indicator */}
      <div className="flex items-center gap-2 mb-6">
        {STEPS.map((s, i) => (
          <div key={s} className="flex items-center gap-2 flex-1">
            <div className={`flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-xs font-bold ${
              i <= step ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'
            }`}>{i + 1}</div>
            {i < STEPS.length - 1 && <div className={`flex-1 h-px ${i < step ? 'bg-primary' : 'bg-border'}`} />}
          </div>
        ))}
      </div>

      <h1 className="text-2xl font-bold text-foreground mb-1">Create Holder Account</h1>
      <p className="text-sm text-muted-foreground mb-6">{STEPS[step]}</p>

      {step === 0 && (
        <form onSubmit={handleFin} className="space-y-4">
          <Input
            label="National ID Number (FIN)"
            placeholder="Enter your FIN"
            value={fin}
            onChange={(e) => setFin(e.target.value)}
            required
            hint="Your national identification number used to verify your identity"
          />
          <Button type="submit" loading={loading} className="w-full">Send OTP</Button>
        </form>
      )}

      {step === 1 && (
        <form onSubmit={handleOtp} className="space-y-4">
          <Input
            label="One-Time Password"
            placeholder="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            maxLength={6}
            required
            hint="OTP sent to your registered phone number"
          />
          <Button type="submit" loading={loading} className="w-full">Verify OTP</Button>
          <button type="button" onClick={() => setStep(0)} className="w-full text-sm text-muted-foreground hover:text-foreground">
            ← Back
          </button>
        </form>
      )}

      {step === 2 && (
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          {nidData && (
            <div className="rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 p-3 mb-4">
              <p className="text-sm text-green-700 dark:text-green-400 font-medium">Identity Verified</p>
              <p className="text-sm text-green-600 dark:text-green-500">{nidData.first_name} {nidData.last_name}</p>
            </div>
          )}
          <Input label="Email" type="email" error={errors.email?.message} {...register('email', { required: 'Email required' })} />
          <Input
            label="Password"
            type="password"
            error={errors.password?.message}
            {...register('password', { required: 'Password required', minLength: { value: 8, message: 'Min 8 characters' } })}
          />
          <Input
            label="Confirm Password"
            type="password"
            error={errors.confirmPassword?.message}
            {...register('confirmPassword', {
              required: 'Please confirm password',
              validate: (v) => v === watch('password') || 'Passwords do not match',
            })}
          />
          <Button type="submit" loading={loading} className="w-full">Create Account</Button>
        </form>
      )}

      <p className="mt-6 text-center text-sm text-muted-foreground">
        Already have an account? <Link to="/login" className="text-primary font-medium hover:underline">Sign in</Link>
      </p>
    </div>
  );
}

import { useState } from 'react';
import { Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import FileUpload from '../../components/common/FileUpload';
import {
  requestEmailVerification, verifyEmail, createOrgAccount,
  saveOrgDetails, saveUseCase, saveAuthorization, uploadDocument, submitApplication,
} from '../../api/auth';
import toast from 'react-hot-toast';
import { CheckCircle } from 'lucide-react';

const STEPS = ['Account', 'Email OTP', 'Org Details', 'Documents', 'Use Case', 'Submit'];

export default function OrgRegisterPage() {
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [otp, setOtp] = useState('');
  const [orgId, setOrgId] = useState(null);
  const [docs, setDocs] = useState([]);
  const [formData, setFormData] = useState({ email: '', org_type: 'issuer' });
  const { register, handleSubmit, formState: { errors }, watch, getValues } = useForm();

  const next = () => setStep((s) => s + 1);

  // Step 0: Account creation + email verification request
  const handleAccount = async (data) => {
    setLoading(true);
    try {
      setFormData({ ...formData, ...data });
      await requestEmailVerification({ email: data.email });
      toast.success('Verification email sent');
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to send verification email');
    } finally { setLoading(false); }
  };

  // Step 1: Verify email OTP
  const handleEmailOtp = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await verifyEmail({ email: formData.email, otp });
      await createOrgAccount({ email: formData.email, password: formData.password, first_name: formData.first_name, last_name: formData.last_name, org_type: formData.org_type });
      toast.success('Account created');
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Invalid OTP or account creation failed');
    } finally { setLoading(false); }
  };

  // Step 2: Org details
  const handleOrgDetails = async (data) => {
    setLoading(true);
    try {
      const res = await saveOrgDetails(data);
      setOrgId(res.data?.organization_id || res.data?.id);
      toast.success('Details saved');
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save details');
    } finally { setLoading(false); }
  };

  // Step 3: Documents
  const handleDocs = async () => {
    if (docs.length === 0) { toast.error('Please upload at least one document'); return; }
    setLoading(true);
    try {
      const fd = new FormData();
      docs.forEach((f) => fd.append('documents', f));
      if (orgId) fd.append('organization_id', orgId);
      await uploadDocument(fd);
      toast.success('Documents uploaded');
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Upload failed');
    } finally { setLoading(false); }
  };

  // Step 4: Use case
  const handleUseCase = async (data) => {
    setLoading(true);
    try {
      await saveUseCase({ ...data, organization_id: orgId });
      await saveAuthorization({ organization_id: orgId, agreed: true });
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save use case');
    } finally { setLoading(false); }
  };

  // Step 5: Submit
  const handleSubmitApp = async () => {
    setLoading(true);
    try {
      await submitApplication({ organization_id: orgId });
      toast.success('Application submitted! You will be notified upon approval.');
      next();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Submission failed');
    } finally { setLoading(false); }
  };

  const submitted = step >= STEPS.length;

  return (
    <div className="max-w-lg mx-auto">
      {/* Step indicator */}
      <div className="flex items-center gap-1 mb-6 flex-wrap">
        {STEPS.map((s, i) => (
          <div key={s} className="flex items-center gap-1">
            <div className={`flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold ${
              i <= step ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'
            }`}>{i + 1}</div>
            {i < STEPS.length - 1 && <div className={`h-px w-4 ${i < step ? 'bg-primary' : 'bg-border'}`} />}
          </div>
        ))}
      </div>

      {submitted ? (
        <div className="text-center py-8">
          <CheckCircle className="h-16 w-16 text-green-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-foreground mb-2">Application Submitted!</h2>
          <p className="text-muted-foreground mb-6">Your organization is under review. You will receive an email once approved.</p>
          <Link to="/login" className="text-primary font-medium hover:underline">Sign in when approved →</Link>
        </div>
      ) : (
        <>
          <h1 className="text-2xl font-bold text-foreground mb-1">Register Organization</h1>
          <p className="text-sm text-muted-foreground mb-6">Step {step + 1}: {STEPS[step]}</p>

          {step === 0 && (
            <form onSubmit={handleSubmit(handleAccount)} className="space-y-4">
              <Select
                label="Organization Type"
                value={formData.org_type}
                onChange={(e) => setFormData({ ...formData, org_type: e.target.value })}
                options={[{ value: 'issuer', label: 'Issuer — Issue Credentials' }, { value: 'verifier', label: 'Verifier — Verify Credentials' }]}
              />
              <div className="grid grid-cols-2 gap-3">
                <Input label="First Name" error={errors.first_name?.message} {...register('first_name', { required: 'Required' })} />
                <Input label="Last Name" error={errors.last_name?.message} {...register('last_name', { required: 'Required' })} />
              </div>
              <Input label="Email" type="email" error={errors.email?.message} {...register('email', { required: 'Required' })} />
              <Input label="Password" type="password" error={errors.password?.message} {...register('password', { required: 'Required', minLength: { value: 8, message: 'Min 8 chars' } })} />
              <Button type="submit" loading={loading} className="w-full">Send Verification Email</Button>
            </form>
          )}

          {step === 1 && (
            <form onSubmit={handleEmailOtp} className="space-y-4">
              <p className="text-sm text-muted-foreground">Enter the OTP sent to <strong>{formData.email}</strong></p>
              <Input label="Email OTP" value={otp} onChange={(e) => setOtp(e.target.value)} maxLength={6} required />
              <Button type="submit" loading={loading} className="w-full">Verify & Create Account</Button>
            </form>
          )}

          {step === 2 && (
            <form onSubmit={handleSubmit(handleOrgDetails)} className="space-y-4">
              <Input label="Organization Name" error={errors.name?.message} {...register('name', { required: 'Required' })} />
              <Input label="Registration Number" {...register('registration_number')} />
              <Input label="Website" type="url" {...register('website')} />
              <Input label="Phone" type="tel" {...register('phone')} />
              <Textarea label="Address" rows={3} {...register('address')} />
              <Button type="submit" loading={loading} className="w-full">Save Details</Button>
            </form>
          )}

          {step === 3 && (
            <div className="space-y-4">
              <FileUpload
                label="Upload Supporting Documents (PDF, JPG, PNG)"
                onDrop={(f) => setDocs((d) => [...d, ...f])}
                onRemove={(i) => setDocs((d) => d.filter((_, idx) => idx !== i))}
                files={docs}
                multiple
                accept={{ 'application/pdf': [], 'image/*': [] }}
              />
              <Button loading={loading} className="w-full" onClick={handleDocs}>Upload & Continue</Button>
            </div>
          )}

          {step === 4 && (
            <form onSubmit={handleSubmit(handleUseCase)} className="space-y-4">
              <Textarea label="Use Case Description" rows={4} error={errors.use_case?.message} placeholder="Describe how you will use CredWallet..." {...register('use_case', { required: 'Required' })} />
              <Textarea label="Types of Credentials" rows={3} placeholder="List the credentials you plan to issue or verify" {...register('credential_types')} />
              <Button type="submit" loading={loading} className="w-full">Continue</Button>
            </form>
          )}

          {step === 5 && (
            <div className="space-y-4">
              <div className="rounded-lg bg-muted/50 p-4 text-sm text-muted-foreground space-y-2">
                <p>By submitting, you confirm that:</p>
                <ul className="list-disc list-inside space-y-1">
                  <li>All information provided is accurate</li>
                  <li>You agree to the Terms of Service and Privacy Policy</li>
                  <li>You understand your application will be reviewed</li>
                </ul>
              </div>
              <Button loading={loading} className="w-full" onClick={handleSubmitApp}>Submit Application</Button>
            </div>
          )}
        </>
      )}

      <p className="mt-6 text-center text-sm text-muted-foreground">
        Already registered? <Link to="/login" className="text-primary font-medium hover:underline">Sign in</Link>
      </p>
    </div>
  );
}

import { useState } from 'react';
import { Link } from 'react-router-dom';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { forgotPassword } from '../../api/auth';
import { CheckCircle } from 'lucide-react';
import toast from 'react-hot-toast';

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [sent, setSent] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await forgotPassword({ email });
      setSent(true);
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to send reset email');
    } finally {
      setLoading(false);
    }
  };

  if (sent) {
    return (
      <div className="text-center py-4">
        <CheckCircle className="h-12 w-12 text-green-500 mx-auto mb-4" />
        <h2 className="text-xl font-bold text-foreground mb-2">Check your email</h2>
        <p className="text-sm text-muted-foreground mb-4">We sent a password reset link to <strong>{email}</strong></p>
        <Link to="/login" className="text-primary text-sm font-medium hover:underline">← Back to login</Link>
      </div>
    );
  }

  return (
    <div>
      <h1 className="text-2xl font-bold text-foreground mb-1">Forgot Password</h1>
      <p className="text-sm text-muted-foreground mb-6">Enter your email to receive a reset link.</p>
      <form onSubmit={handleSubmit} className="space-y-4">
        <Input label="Email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} required />
        <Button type="submit" loading={loading} className="w-full">Send Reset Link</Button>
      </form>
      <p className="mt-6 text-center text-sm">
        <Link to="/login" className="text-primary font-medium hover:underline">← Back to login</Link>
      </p>
    </div>
  );
}

import { useState } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { resetPassword } from '../../api/auth';
import toast from 'react-hot-toast';

export default function ResetPasswordPage() {
  const [params] = useSearchParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const { register, handleSubmit, watch, formState: { errors } } = useForm();

  const onSubmit = async (data) => {
    setLoading(true);
    try {
      await resetPassword({
        token: params.get('token'),
        uid: params.get('uid'),
        new_password: data.password,
      });
      toast.success('Password reset successfully');
      navigate('/login');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Reset failed. Link may be expired.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <h1 className="text-2xl font-bold text-foreground mb-1">Reset Password</h1>
      <p className="text-sm text-muted-foreground mb-6">Enter your new password below.</p>
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
        <Input
          label="New Password"
          type="password"
          error={errors.password?.message}
          {...register('password', { required: 'Required', minLength: { value: 8, message: 'Min 8 characters' } })}
        />
        <Input
          label="Confirm Password"
          type="password"
          error={errors.confirm?.message}
          {...register('confirm', {
            required: 'Required',
            validate: (v) => v === watch('password') || 'Passwords do not match',
          })}
        />
        <Button type="submit" loading={loading} className="w-full">Reset Password</Button>
      </form>
      <p className="mt-4 text-center text-sm">
        <Link to="/login" className="text-primary font-medium hover:underline">← Back to login</Link>
      </p>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { CreditCard, Share2, ClipboardList, ArrowRight, ShieldCheck } from 'lucide-react';
import { getHolderCredentials } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';
import useAuthStore from '../../store/authStore';

export default function HolderDashboard() {
  const { user } = useAuthStore();
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getHolderCredentials({ page_size: 5 })
      .then((r) => setCredentials(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const active = credentials.filter((c) => c.status === 'active').length;
  const expired = credentials.filter((c) => c.status === 'expired').length;

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Welcome back, {user?.first_name || 'Holder'}!</h1>
        <p className="text-muted-foreground text-sm mt-1">Manage your digital credentials.</p>
      </div>

      {/* Stats */}
      <div className="grid sm:grid-cols-3 gap-4">
        {[
          { label: 'Total Credentials', value: credentials.length, icon: CreditCard, color: 'text-blue-600', bg: 'bg-blue-50 dark:bg-blue-900/20' },
          { label: 'Active', value: active, icon: ShieldCheck, color: 'text-green-600', bg: 'bg-green-50 dark:bg-green-900/20' },
          { label: 'Expired', value: expired, icon: ClipboardList, color: 'text-yellow-600', bg: 'bg-yellow-50 dark:bg-yellow-900/20' },
        ].map((s) => (
          <div key={s.label} className="rounded-xl border border-border bg-card p-5">
            <div className="flex items-center justify-between mb-3">
              <span className="text-sm text-muted-foreground">{s.label}</span>
              <div className={`rounded-lg p-2 ${s.bg}`}>
                <s.icon className={`h-4 w-4 ${s.color}`} />
              </div>
            </div>
            <p className="text-3xl font-bold text-foreground">{loading ? '...' : s.value}</p>
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div className="grid sm:grid-cols-3 gap-4">
        {[
          { to: '/holder/credentials/request', icon: CreditCard, label: 'Request Credential', desc: 'Ask an issuer for a credential' },
          { to: '/holder/credentials', icon: ShieldCheck, label: 'My Credentials', desc: 'View and manage all credentials' },
          { to: '/holder/shares', icon: Share2, label: 'Shared Links', desc: 'Manage your share links' },
        ].map((a) => (
          <Link key={a.to} to={a.to} className="flex items-center gap-4 rounded-xl border border-border bg-card p-4 hover:bg-muted/30 transition-colors group">
            <div className="rounded-xl bg-primary/10 p-3 shrink-0">
              <a.icon className="h-5 w-5 text-primary" />
            </div>
            <div className="flex-1">
              <p className="font-medium text-foreground text-sm">{a.label}</p>
              <p className="text-xs text-muted-foreground">{a.desc}</p>
            </div>
            <ArrowRight className="h-4 w-4 text-muted-foreground group-hover:text-foreground transition-colors" />
          </Link>
        ))}
      </div>

      {/* Recent Credentials */}
      <div className="rounded-xl border border-border bg-card">
        <div className="flex items-center justify-between p-4 border-b border-border">
          <h2 className="font-semibold text-foreground">Recent Credentials</h2>
          <Link to="/holder/credentials" className="text-sm text-primary hover:underline">View all →</Link>
        </div>
        <div className="divide-y divide-border">
          {loading ? (
            <div className="p-4 space-y-3">
              {[1, 2, 3].map((i) => <CardSkeleton key={i} />)}
            </div>
          ) : credentials.length === 0 ? (
            <div className="py-10 text-center text-sm text-muted-foreground">
              No credentials yet.{' '}
              <Link to="/holder/credentials/request" className="text-primary hover:underline">Request one →</Link>
            </div>
          ) : (
            credentials.slice(0, 5).map((c) => (
              <Link key={c.id} to={`/holder/credentials/${c.id}`} className="flex items-center justify-between p-4 hover:bg-muted/30 transition-colors">
                <div>
                  <p className="font-medium text-sm text-foreground">{c.credential_type_name || c.type || 'Credential'}</p>
                  <p className="text-xs text-muted-foreground">{c.issuer_name || '—'} • {formatDate(c.issued_at || c.issuanceDate)}</p>
                </div>
                <StatusBadge status={c.status} />
              </Link>
            ))
          )}
        </div>
      </div>
