import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { Plus, CreditCard } from 'lucide-react';
import { getHolderCredentials } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import SearchInput from '../../components/common/SearchInput';
import Pagination from '../../components/common/Pagination';
import EmptyState from '../../components/common/EmptyState';
import { TableSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';
import useDebounce from '../../hooks/useDebounce';

export default function CredentialsPage() {
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const debouncedSearch = useDebounce(search);

  useEffect(() => {
    setLoading(true);
    getHolderCredentials({ search: debouncedSearch, page, page_size: 20 })
      .then((r) => {
        const data = r.data;
        setCredentials(data?.results || data || []);
        setTotalPages(Math.ceil((data?.count || (data?.results || data || []).length) / 20));
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [debouncedSearch, page]);

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-foreground">My Credentials</h1>
        <Link to="/holder/credentials/request">
          <Button size="sm"><Plus className="h-4 w-4" />Request Credential</Button>
        </Link>
      </div>

      <SearchInput value={search} onChange={setSearch} placeholder="Search credentials..." />

      {loading ? (
        <TableSkeleton rows={5} cols={4} />
      ) : credentials.length === 0 ? (
        <EmptyState
          icon={CreditCard}
          title="No credentials found"
          description="You don't have any credentials yet. Request one from an issuer."
          action={<Link to="/holder/credentials/request"><Button size="sm"><Plus className="h-4 w-4" />Request Credential</Button></Link>}
        />
      ) : (
        <>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {credentials.map((c) => (
              <Link key={c.id} to={`/holder/credentials/${c.id}`} className="rounded-xl border border-border bg-card p-5 hover:shadow-md transition-shadow group">
                <div className="flex items-start justify-between mb-4">
                  <div className="rounded-xl bg-primary/10 p-3">
                    <CreditCard className="h-5 w-5 text-primary" />
                  </div>
                  <StatusBadge status={c.status} />
                </div>
                <h3 className="font-semibold text-foreground text-sm mb-1">{c.credential_type_name || c.type || 'Credential'}</h3>
                <p className="text-xs text-muted-foreground mb-2">Issued by {c.issuer_name || '—'}</p>
                <div className="flex items-center justify-between text-xs text-muted-foreground">
                  <span>Issued: {formatDate(c.issued_at || c.issuanceDate)}</span>
                  {c.expiration_date && <span>Expires: {formatDate(c.expiration_date)}</span>}
                </div>
              </Link>
            ))}
          </div>
          <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />
        </>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Share2, Download, ArrowLeft, QrCode } from 'lucide-react';
import { getHolderCredential, createShare } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Modal from '../../components/common/Modal';
import { FullPageSpinner } from '../../components/common/Spinner';
import { formatDate, formatDateTime } from '../../utils/formatDate';
import { flattenClaims } from '../../utils/claimsUtils';
import toast from 'react-hot-toast';
import QRCode from 'qrcode';

export default function CredentialDetailPage() {
  const { id } = useParams();
  const [credential, setCredential] = useState(null);
  const [loading, setLoading] = useState(true);
  const [shareModal, setShareModal] = useState(false);
  const [qrModal, setQrModal] = useState(false);
  const [qrUrl, setQrUrl] = useState('');
  const [shareLoading, setShareLoading] = useState(false);
  const [shareResult, setShareResult] = useState(null);

  useEffect(() => {
    getHolderCredential(id)
      .then((r) => setCredential(r.data))
      .catch(() => toast.error('Failed to load credential'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleShare = async (expiryHours = 24) => {
    setShareLoading(true);
    try {
      const res = await createShare(id, { expiry_hours: expiryHours });
      setShareResult(res.data);
      const url = `${window.location.origin}/verify/${res.data.token || res.data.share_token}`;
      const qr = await QRCode.toDataURL(url, { width: 300 });
      setQrUrl(qr);
      toast.success('Share link created');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to create share link');
    } finally {
      setShareLoading(false);
    }
  };

  if (loading) return <FullPageSpinner />;
  if (!credential) return <div className="text-center py-16 text-muted-foreground">Credential not found.</div>;

  const claims = flattenClaims(credential.credential_data?.credentialSubject || credential.credentialSubject || credential.claims || {});

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="flex items-center gap-3">
        <Link to="/holder/credentials">
          <Button variant="ghost" size="sm"><ArrowLeft className="h-4 w-4" />Back</Button>
        </Link>
      </div>

      {/* Credential header */}
      <div className="rounded-2xl border border-border bg-card p-6">
        <div className="flex items-start justify-between mb-4">
          <div>
            <h1 className="text-xl font-bold text-foreground">{credential.credential_type_name || credential.type || 'Credential'}</h1>
            <p className="text-sm text-muted-foreground mt-1">Issued by <strong>{credential.issuer_name || '—'}</strong></p>
          </div>
          <StatusBadge status={credential.status} />
        </div>
        <div className="grid sm:grid-cols-2 gap-3 text-sm mb-4">
          <div><span className="text-muted-foreground">Issued:</span> <span className="text-foreground font-medium">{formatDate(credential.issued_at || credential.issuanceDate)}</span></div>
          {credential.expiration_date && (
            <div><span className="text-muted-foreground">Expires:</span> <span className="text-foreground font-medium">{formatDate(credential.expiration_date)}</span></div>
          )}
          {credential.credential_id && (
            <div className="col-span-2"><span className="text-muted-foreground">ID:</span> <span className="font-mono text-xs text-foreground">{credential.credential_id || credential.id}</span></div>
          )}
        </div>
        <div className="flex gap-2">
          <Button size="sm" onClick={() => { setShareModal(true); }} disabled={credential.status !== 'active'}>
            <Share2 className="h-4 w-4" />Share
          </Button>
          {qrUrl && (
            <Button size="sm" variant="outline" onClick={() => setQrModal(true)}>
              <QrCode className="h-4 w-4" />QR Code
            </Button>
          )}
        </div>
      </div>

      {/* Claims */}
      {claims.length > 0 && (
        <div className="rounded-xl border border-border bg-card p-5">
          <h2 className="font-semibold text-foreground mb-4">Credential Claims</h2>
          <dl className="divide-y divide-border">
            {claims.map((c) => (
              <div key={c.key} className="flex items-start justify-between py-3">
                <dt className="text-sm text-muted-foreground">{c.label}</dt>
                <dd className="text-sm font-medium text-foreground max-w-xs text-right">{c.value}</dd>
              </div>
            ))}
          </dl>
        </div>
      )}

      {/* Share Modal */}
      <Modal open={shareModal} onClose={() => { setShareModal(false); setShareResult(null); }} title="Share Credential">
        {!shareResult ? (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">Choose how long the share link stays active.</p>
            <div className="grid grid-cols-3 gap-3">
              {[{ h: 1, label: '1 Hour' }, { h: 24, label: '24 Hours' }, { h: 168, label: '7 Days' }].map((opt) => (
                <Button key={opt.h} variant="outline" loading={shareLoading} onClick={() => handleShare(opt.h)}>{opt.label}</Button>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="rounded-lg bg-muted p-3">
              <p className="text-xs text-muted-foreground mb-1">Share Link</p>
              <p className="font-mono text-xs break-all text-foreground">{`${window.location.origin}/verify/${shareResult.token || shareResult.share_token}`}</p>
            </div>
            {qrUrl && <img src={qrUrl} alt="QR Code" className="mx-auto rounded-lg w-48 h-48" />}
            <Button className="w-full" onClick={() => {
              navigator.clipboard.writeText(`${window.location.origin}/verify/${shareResult.token || shareResult.share_token}`);
              toast.success('Link copied!');
            }}>Copy Link</Button>
          </div>
        )}
      </Modal>

      <Modal open={qrModal} onClose={() => setQrModal(false)} title="QR Code">
        {qrUrl && <img src={qrUrl} alt="QR Code" className="mx-auto w-64 h-64" />}
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { getRequestCatalog } from '../../api/holder';
import { getTemplates } from '../../api/issuer';
import { createHolderRequest } from '../../api/holder';
import Select from '../../components/common/Select';
import Textarea from '../../components/common/Textarea';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

export default function RequestCredentialPage() {
  const navigate = useNavigate();
  const [credTypes, setCredTypes] = useState([]);
  const [loading, setLoading] = useState(false);
  const { register, handleSubmit, formState: { errors } } = useForm();

  useEffect(() => {
    getRequestCatalog()
      .then((r) => setCredTypes(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  const onSubmit = async (data) => {
    setLoading(true);
    try {
      await createHolderRequest(data);
      toast.success('Credential request submitted');
      navigate('/holder/requests');
    } catch (err) {
      toast.error(err.response?.data?.detail || Object.values(err.response?.data || {})[0]?.[0] || 'Failed to submit request');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto">
      <h1 className="text-2xl font-bold text-foreground mb-2">Request a Credential</h1>
      <p className="text-muted-foreground text-sm mb-6">Submit a request to an issuer for a credential.</p>

      <div className="rounded-xl border border-border bg-card p-6">
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
          <Select
            label="Credential Type"
            placeholder="Select a credential type"
            options={credTypes.map((t) => ({ value: t.id, label: t.name }))}
            error={errors.credential_type?.message}
            {...register('credential_type', { required: 'Please select a credential type' })}
          />
          <Textarea
            label="Message to Issuer (optional)"
            placeholder="Add any details or context for your request..."
            rows={4}
            {...register('message')}
          />
          <div className="flex gap-3">
            <Button type="button" variant="outline" onClick={() => navigate(-1)}>Cancel</Button>
            <Button type="submit" loading={loading} className="flex-1">Submit Request</Button>
          </div>
        </form>
      </div>
    </div>
  );
}

