import { useEffect, useState } from 'react';
import { Link2, Copy, Trash2, QrCode } from 'lucide-react';
import { getShares } from '../../api/holder';
import { formatDateTime, isExpired } from '../../utils/formatDate';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

export default function SharesPage() {
  const [shares, setShares] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getShares()
      .then((r) => setShares(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const copy = (token) => {
    navigator.clipboard.writeText(`${window.location.origin}/verify/${token}`);
    toast.success('Link copied!');
  };

  return (
    <div className="space-y-5">
      <h1 className="text-2xl font-bold text-foreground">Shared Links</h1>
      {loading ? (
        <p className="text-muted-foreground text-sm">Loading...</p>
      ) : shares.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <Link2 className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="text-muted-foreground text-sm">No shared links yet. Share a credential to create one.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {shares.map((s) => {
            const expired = isExpired(s.expires_at);
            return (
              <div key={s.id} className={`rounded-xl border bg-card p-4 ${expired ? 'border-border opacity-60' : 'border-border'}`}>
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-sm text-foreground truncate">{s.credential_type_name || 'Credential'}</p>
                    <p className="text-xs text-muted-foreground font-mono mt-0.5 truncate">{s.token || s.share_token}</p>
                    <div className="flex gap-3 mt-1 text-xs text-muted-foreground">
                      <span>Views: {s.access_count || 0}</span>
                      <span>Expires: {s.expires_at ? formatDateTime(s.expires_at) : 'Never'}</span>
                      {expired && <span className="text-yellow-600 font-medium">Expired</span>}
                    </div>
                  </div>
                  <div className="flex gap-1 shrink-0">
                    <Button size="icon" variant="ghost" onClick={() => copy(s.token || s.share_token)} title="Copy link">
                      <Copy className="h-4 w-4 text-muted-foreground" />
                    </Button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

