import { useEffect, useState } from 'react';
import { Bell, Check, Trash2 } from 'lucide-react';
import { getHolderNotifications, markHolderNotificationRead, markAllHolderNotificationsRead, deleteHolderNotification } from '../../api/holder';
import { formatRelative } from '../../utils/formatDate';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

export default function HolderNotifications() {
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    getHolderNotifications()
      .then((r) => setNotifications(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const markRead = async (id) => {
    try {
      await markHolderNotificationRead(id);
      setNotifications((n) => n.map((x) => x.id === id ? { ...x, is_read: true } : x));
    } catch { }
  };

  const markAll = async () => {
    try {
      await markAllHolderNotificationsRead();
      setNotifications((n) => n.map((x) => ({ ...x, is_read: true })));
      toast.success('All marked as read');
    } catch { }
  };

  const remove = async (id) => {
    try {
      await deleteHolderNotification(id);
      setNotifications((n) => n.filter((x) => x.id !== id));
    } catch { }
  };

  const unread = notifications.filter((n) => !n.is_read).length;

  return (
    <div className="space-y-5 max-w-2xl">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Notifications</h1>
          {unread > 0 && <p className="text-sm text-muted-foreground">{unread} unread</p>}
        </div>
        {unread > 0 && (
          <Button size="sm" variant="outline" onClick={markAll}><Check className="h-4 w-4" />Mark all read</Button>
        )}
      </div>

      {loading ? (
        <p className="text-muted-foreground text-sm">Loading...</p>
      ) : notifications.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <Bell className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="text-muted-foreground text-sm">No notifications</p>
        </div>
      ) : (
        <div className="space-y-2">
          {notifications.map((n) => (
            <div key={n.id} className={`flex items-start gap-3 rounded-xl border border-border bg-card p-4 ${!n.is_read ? 'bg-primary/5 border-primary/20' : ''}`}>
              {!n.is_read && <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-primary" />}
              {n.is_read && <div className="mt-1.5 h-2 w-2 shrink-0" />}
              <div className="flex-1">
                <p className="text-sm font-medium text-foreground">{n.title || n.message}</p>
                {n.body && <p className="text-xs text-muted-foreground mt-0.5">{n.body}</p>}
                <p className="text-xs text-muted-foreground mt-1">{formatRelative(n.created_at)}</p>
              </div>
              <div className="flex gap-1">
                {!n.is_read && (
                  <Button size="icon" variant="ghost" onClick={() => markRead(n.id)} title="Mark read">
                    <Check className="h-4 w-4 text-muted-foreground" />
                  </Button>
                )}
                <Button size="icon" variant="ghost" onClick={() => remove(n.id)} title="Delete">
                  <Trash2 className="h-4 w-4 text-muted-foreground" />
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
