import { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { Plus, Trash2, ArrowLeft } from 'lucide-react';
import {
  getTemplate, createTemplate, updateTemplate,
  getTemplateFields, createTemplateField, deleteTemplateField,
  getCredentialTypes,
} from '../../api/issuer';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import { FullPageSpinner } from '../../components/common/Spinner';
import toast from 'react-hot-toast';

const FIELD_TYPES = [
  { value: 'text', label: 'Text' },
  { value: 'number', label: 'Number' },
  { value: 'date', label: 'Date' },
  { value: 'boolean', label: 'Boolean' },
  { value: 'email', label: 'Email' },
  { value: 'url', label: 'URL' },
];

export default function TemplateEditorPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;

  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [credTypes, setCredTypes] = useState([]);
  const [fields, setFields] = useState([]);
  const [newField, setNewField] = useState({ name: '', label: '', field_type: 'text', required: false });
  const [addingField, setAddingField] = useState(false);

  const { register, handleSubmit, reset, formState: { errors } } = useForm();

  useEffect(() => {
    getCredentialTypes().then((r) => setCredTypes(r.data?.results || r.data || [])).catch(() => {});
    if (isEdit) {
      Promise.all([getTemplate(id), getTemplateFields(id)])
        .then(([tmpl, flds]) => {
          const t = tmpl.data;
          reset({ name: t.name, description: t.description, credential_type: t.credential_type, is_active: t.is_active });
          setFields(flds.data?.results || flds.data || []);
        })
        .catch(() => toast.error('Failed to load template'))
        .finally(() => setLoading(false));
    }
  }, [id]);

  const onSubmit = async (data) => {
    setSaving(true);
    try {
      if (isEdit) {
        await updateTemplate(id, data);
        toast.success('Template updated');
      } else {
        const res = await createTemplate(data);
        toast.success('Template created');
        navigate(`/issuer/templates/${res.data.id}/edit`);
        return;
      }
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Save failed');
    } finally { setSaving(false); }
  };

  const handleAddField = async () => {
    if (!newField.name || !id) return;
    setAddingField(true);
    try {
      const res = await createTemplateField(id, newField);
      setFields((f) => [...f, res.data]);
      setNewField({ name: '', label: '', field_type: 'text', required: false });
      toast.success('Field added');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to add field');
    } finally { setAddingField(false); }
  };

  const handleDeleteField = async (fieldId) => {
    try {
      await deleteTemplateField(id, fieldId);
      setFields((f) => f.filter((x) => x.id !== fieldId));
    } catch { toast.error('Failed to delete field'); }
  };

  if (loading) return <FullPageSpinner />;

  return (
    <div className="max-w-2xl space-y-6">
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/issuer/templates')}>
          <ArrowLeft className="h-4 w-4" />Back
        </Button>
        <h1 className="text-xl font-bold text-foreground">{isEdit ? 'Edit Template' : 'New Template'}</h1>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="rounded-xl border border-border bg-card p-6 space-y-4">
        <Input label="Template Name" error={errors.name?.message} {...register('name', { required: 'Required' })} />
        <Select
          label="Credential Type"
          placeholder="Select credential type"
          options={credTypes.map((t) => ({ value: t.id, label: t.name }))}
          {...register('credential_type')}
        />
        <Textarea label="Description" rows={3} {...register('description')} />
        <div className="flex items-center gap-2">
          <input type="checkbox" id="is_active" {...register('is_active')} className="rounded" />
          <label htmlFor="is_active" className="text-sm text-foreground">Active</label>
        </div>
        <Button type="submit" loading={saving}>{isEdit ? 'Save Changes' : 'Create Template'}</Button>
      </form>

      {isEdit && (
        <div className="rounded-xl border border-border bg-card p-6 space-y-4">
          <h2 className="font-semibold text-foreground">Template Fields</h2>
          {fields.length > 0 && (
            <div className="space-y-2">
              {fields.map((f) => (
                <div key={f.id} className="flex items-center justify-between rounded-lg border border-border px-3 py-2">
                  <div className="flex gap-3 text-sm">
                    <span className="font-medium text-foreground">{f.label || f.name}</span>
                    <span className="text-muted-foreground">{f.field_type}</span>
                    {f.required && <span className="text-xs text-red-500">required</span>}
                  </div>
                  <Button size="icon" variant="ghost" onClick={() => handleDeleteField(f.id)}>
                    <Trash2 className="h-4 w-4 text-destructive" />
                  </Button>
                </div>
              ))}
            </div>
          )}

          <div className="rounded-lg border border-dashed border-border p-4 space-y-3">
            <p className="text-sm font-medium text-foreground">Add Field</p>
            <div className="grid grid-cols-2 gap-3">
              <Input placeholder="Field name (key)" value={newField.name} onChange={(e) => setNewField({ ...newField, name: e.target.value })} />
              <Input placeholder="Label" value={newField.label} onChange={(e) => setNewField({ ...newField, label: e.target.value })} />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <Select
                options={FIELD_TYPES}
                value={newField.field_type}
                onChange={(e) => setNewField({ ...newField, field_type: e.target.value })}
              />
              <div className="flex items-center gap-2 h-10">
                <input type="checkbox" id="req" checked={newField.required} onChange={(e) => setNewField({ ...newField, required: e.target.checked })} className="rounded" />
                <label htmlFor="req" className="text-sm text-foreground">Required</label>
              </div>
            </div>
            <Button size="sm" onClick={handleAddField} loading={addingField} disabled={!newField.name}>
              <Plus className="h-4 w-4" />Add Field
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

