  const [holderInfo, setHolderInfo] = useState(null);
  const [lookupLoading, setLookupLoading] = useState(false);

  const { register, handleSubmit, setValue, formState: { errors } } = useForm();

  useEffect(() => {
    getTemplates({ is_active: true })
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedTemplate) { setFields([]); return; }
    setLoadingFields(true);
    getTemplateFields(selectedTemplate)
      .then((r) => setFields(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoadingFields(false));
  }, [selectedTemplate]);

  const handleHolderLookup = async () => {
    if (!holderLookup) return;
    setLookupLoading(true);
    try {
      const res = await lookupHolder({ fin: holderLookup });
      setHolderInfo(res.data);
      toast.success('Holder found');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Holder not found');
    } finally { setLookupLoading(false); }
  };

  const onSubmit = async (data) => {
    if (!selectedTemplate) { toast.error('Please select a template'); return; }
    setIssuing(true);
    try {
      const payload = {
        holder_fin: holderLookup || undefined,
        holder_email: data.holder_email || undefined,
        expiry_date: data.expiry_date || undefined,
        claims: {},
      };
      fields.forEach((f) => {
        if (data[`field_${f.name}`] !== undefined) {
          payload.claims[f.name] = data[`field_${f.name}`];
        }
      });
      await issueCredential(selectedTemplate, payload);
      toast.success('Credential issued successfully');
      navigate('/issuer/issued');
    } catch (err) {
      toast.error(err.response?.data?.detail || Object.values(err.response?.data || {})[0]?.[0] || 'Failed to issue credential');
    } finally { setIssuing(false); }
  };

  return (
    <div className="max-w-2xl space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-foreground">Issue Credential</h1>
        <Link to="/issuer/issue/bulk">
          <Button variant="outline" size="sm"><UploadCloud className="h-4 w-4" />Bulk Issue</Button>
        </Link>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
        {/* Template selection */}
        <div className="rounded-xl border border-border bg-card p-5 space-y-4">
          <h2 className="font-semibold text-foreground">1. Select Template</h2>
          <Select
            label="Template"
            placeholder="Choose a template"
            value={selectedTemplate}
            onChange={(e) => setSelectedTemplate(e.target.value)}
            options={templates.map((t) => ({ value: t.id, label: t.name }))}
          />
        </div>

        {/* Holder identification */}
        <div className="rounded-xl border border-border bg-card p-5 space-y-4">
          <h2 className="font-semibold text-foreground">2. Identify Holder</h2>
          <div className="flex gap-2">
            <Input
              label="National ID (FIN)"
              placeholder="Enter holder's FIN"
              value={holderLookup}
              onChange={(e) => setHolderLookup(e.target.value)}
              className="flex-1"
            />
            <div className="mt-7">
              <Button type="button" variant="outline" size="sm" loading={lookupLoading} onClick={handleHolderLookup}>
                Lookup
              </Button>
            </div>
          </div>
          {holderInfo && (
            <div className="rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 p-3 text-sm">
              <p className="text-green-700 dark:text-green-400 font-medium">Holder Found</p>
              <p className="text-green-600 dark:text-green-500">{holderInfo.first_name} {holderInfo.last_name} — {holderInfo.email}</p>
            </div>
          )}
          <Input label="Or Holder Email" type="email" {...register('holder_email')} placeholder="Alternative: enter email" />
          <Input label="Expiry Date (optional)" type="date" {...register('expiry_date')} />
        </div>

        {/* Dynamic fields */}
        {fields.length > 0 && (
          <div className="rounded-xl border border-border bg-card p-5 space-y-4">
            <h2 className="font-semibold text-foreground">3. Credential Claims</h2>
            {fields.map((f) => (
              <Input
                key={f.id}
                label={`${f.label || f.name}${f.required ? ' *' : ''}`}
                type={f.field_type === 'date' ? 'date' : f.field_type === 'number' ? 'number' : f.field_type === 'email' ? 'email' : 'text'}
                error={errors[`field_${f.name}`]?.message}
                {...register(`field_${f.name}`, { required: f.required ? `${f.label || f.name} is required` : false })}
              />
            ))}
          </div>
        )}

        <Button type="submit" loading={issuing} disabled={!selectedTemplate} className="w-full">
          Issue Credential
        </Button>
      </form>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTemplates, bulkValidate, bulkIssue } from '../../api/issuer';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import FileUpload from '../../components/common/FileUpload';
import Table from '../../components/common/Table';
import { CheckCircle, XCircle } from 'lucide-react';
import toast from 'react-hot-toast';

export default function BulkIssuancePage() {
  const navigate = useNavigate();
  const [templates, setTemplates] = useState([]);
  const [selectedTemplate, setSelectedTemplate] = useState('');
  const [files, setFiles] = useState([]);
  const [validating, setValidating] = useState(false);
  const [issuing, setIssuing] = useState(false);
  const [validationResult, setValidationResult] = useState(null);

  useEffect(() => {
    getTemplates({ is_active: true })
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  const handleValidate = async () => {
    if (!selectedTemplate || files.length === 0) {
      toast.error('Select a template and upload a CSV file');
      return;
    }
    setValidating(true);
    const fd = new FormData();
    fd.append('file', files[0]);
    try {
      const res = await bulkValidate(selectedTemplate, fd);
      setValidationResult(res.data);
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Validation failed');
    } finally { setValidating(false); }
  };

  const handleIssue = async () => {
    if (!selectedTemplate || files.length === 0) return;
    setIssuing(true);
    const fd = new FormData();
    fd.append('file', files[0]);
    try {
      const res = await bulkIssue(selectedTemplate, fd);
      toast.success(`Issued ${res.data?.issued_count || 'all'} credentials`);
      navigate('/issuer/issued');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Bulk issuance failed');
    } finally { setIssuing(false); }
  };

  const resultColumns = [
    { key: 'row', label: 'Row' },
    { key: 'holder', label: 'Holder' },
    { key: 'valid', label: 'Valid', render: (v) => v ? <CheckCircle className="h-4 w-4 text-green-500" /> : <XCircle className="h-4 w-4 text-red-500" /> },
    { key: 'error', label: 'Error', render: (v) => v ? <span className="text-xs text-red-500">{v}</span> : '—' },
  ];

  return (
    <div className="max-w-3xl space-y-6">
      <h1 className="text-2xl font-bold text-foreground">Bulk Issue Credentials</h1>
      <div className="rounded-xl border border-border bg-card p-6 space-y-5">
        <Select
          label="Template"
          placeholder="Select a template"
          value={selectedTemplate}
          onChange={(e) => { setSelectedTemplate(e.target.value); setValidationResult(null); }}
          options={templates.map((t) => ({ value: t.id, label: t.name }))}
        />
        <FileUpload
          label="Upload CSV File"
          accept={{ 'text/csv': ['.csv'] }}
          files={files}
          onDrop={(f) => { setFiles(f.slice(0, 1)); setValidationResult(null); }}
          onRemove={() => { setFiles([]); setValidationResult(null); }}
        />
        <div className="rounded-lg bg-muted/50 p-3 text-xs text-muted-foreground">
          CSV must include a header row with column names matching the template fields. Include a <code>holder_email</code> or <code>holder_fin</code> column.
        </div>
        <div className="flex gap-3">
          <Button variant="outline" onClick={handleValidate} loading={validating} disabled={!selectedTemplate || files.length === 0}>
            Validate CSV
          </Button>
          <Button onClick={handleIssue} loading={issuing} disabled={!selectedTemplate || files.length === 0 || (validationResult && validationResult.has_errors)}>
            Issue All
          </Button>
        </div>
      </div>

      {validationResult && (
        <div className="rounded-xl border border-border bg-card p-5">
          <div className="flex items-center justify-between mb-3">
            <h2 className="font-semibold text-foreground">Validation Results</h2>
            <div className="flex gap-3 text-sm">
              <span className="text-green-600">{validationResult.valid_count} valid</span>
              <span className="text-red-600">{validationResult.error_count} errors</span>
            </div>
          </div>
          <Table columns={resultColumns} data={validationResult.rows || []} />
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getIssuedCredentials, revokeIssuedCredential } from '../../api/issuer';
import Table from '../../components/common/Table';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import SearchInput from '../../components/common/SearchInput';
import Pagination from '../../components/common/Pagination';
import Modal from '../../components/common/Modal';
import Textarea from '../../components/common/Textarea';
import { formatDate } from '../../utils/formatDate';
import useDebounce from '../../hooks/useDebounce';
import toast from 'react-hot-toast';

export default function IssuedCredentialsPage() {
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [revokeId, setRevokeId] = useState(null);
  const [reason, setReason] = useState('');
  const [revoking, setRevoking] = useState(false);
  const debouncedSearch = useDebounce(search);

  const load = () => {
    setLoading(true);
    getIssuedCredentials({ search: debouncedSearch, page, page_size: 20 })
      .then((r) => {
        const data = r.data;
        setCredentials(data?.results || data || []);
        setTotalPages(Math.ceil((data?.count || 1) / 20));
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [debouncedSearch, page]);

  const handleRevoke = async () => {
    setRevoking(true);
    try {
      await revokeIssuedCredential(revokeId, { reason });
      toast.success('Credential revoked');
      setRevokeId(null);
      setReason('');
      load();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to revoke');
    } finally { setRevoking(false); }
  };

  const columns = [
    { key: 'credential_type_name', label: 'Type', render: (v, row) => <Link to={`/issuer/issued/${row.id}`} className="font-medium text-primary hover:underline">{v || '—'}</Link> },
    { key: 'holder_name', label: 'Holder', render: (v, row) => v || row.holder_email || '—' },
    { key: 'status', label: 'Status', render: (v) => <StatusBadge status={v} /> },
    { key: 'issued_at', label: 'Issued', render: (v) => formatDate(v) },
    { key: 'expiration_date', label: 'Expires', render: (v) => v ? formatDate(v) : '—' },
    {
      key: 'id',
      label: 'Actions',
      render: (v, row) => row.status === 'active' ? (
        <Button size="sm" variant="outline" onClick={() => setRevokeId(v)} className="text-red-600 border-red-200 hover:bg-red-50">Revoke</Button>
      ) : null,
    },
  ];

  return (
    <div className="space-y-5">
      <h1 className="text-2xl font-bold text-foreground">Issued Credentials</h1>
      <SearchInput value={search} onChange={setSearch} placeholder="Search by holder or type..." />
      <Table columns={columns} data={credentials} loading={loading} emptyMessage="No credentials issued yet." />
      <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />

      <Modal open={!!revokeId} onClose={() => { setRevokeId(null); setReason(''); }} title="Revoke Credential" size="sm">
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">This action cannot be undone. The credential will be immediately invalidated.</p>
          <Textarea label="Reason for revocation" rows={3} value={reason} onChange={(e) => setReason(e.target.value)} placeholder="Enter reason..." />
          <div className="flex justify-end gap-3">
            <Button variant="outline" onClick={() => { setRevokeId(null); setReason(''); }}>Cancel</Button>
            <Button variant="danger" loading={revoking} onClick={handleRevoke}>Revoke</Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';
import { getIssuedCredential } from '../../api/issuer';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import { FullPageSpinner } from '../../components/common/Spinner';
import { formatDate, formatDateTime } from '../../utils/formatDate';
import { flattenClaims } from '../../utils/claimsUtils';
import toast from 'react-hot-toast';

export default function IssuerCredentialDetail() {
  const { id } = useParams();
  const [credential, setCredential] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getIssuedCredential(id)
      .then((r) => setCredential(r.data))
      .catch(() => toast.error('Failed to load credential'))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <FullPageSpinner />;
  if (!credential) return <div className="py-16 text-center text-muted-foreground">Credential not found.</div>;

  const claims = flattenClaims(credential.credential_data?.credentialSubject || credential.claims || {});

  return (
    <div className="max-w-2xl space-y-6">
      <Link to="/issuer/issued">
        <Button variant="ghost" size="sm"><ArrowLeft className="h-4 w-4" />Back</Button>
      </Link>

      <div className="rounded-2xl border border-border bg-card p-6">
        <div className="flex items-start justify-between mb-4">
          <div>
            <h1 className="text-xl font-bold text-foreground">{credential.credential_type_name || credential.type || 'Credential'}</h1>
            <p className="text-sm text-muted-foreground mt-1">Holder: <strong>{credential.holder_name || credential.holder_email || '—'}</strong></p>
          </div>
          <StatusBadge status={credential.status} />
        </div>
        <dl className="grid sm:grid-cols-2 gap-3 text-sm">
          <div><dt className="text-muted-foreground">Issued</dt><dd className="font-medium text-foreground">{formatDateTime(credential.issued_at)}</dd></div>
          {credential.expiration_date && <div><dt className="text-muted-foreground">Expires</dt><dd className="font-medium text-foreground">{formatDate(credential.expiration_date)}</dd></div>}
          {credential.revoked_at && <div><dt className="text-muted-foreground">Revoked</dt><dd className="font-medium text-foreground">{formatDateTime(credential.revoked_at)}</dd></div>}
          {credential.revocation_reason && <div className="col-span-2"><dt className="text-muted-foreground">Revocation Reason</dt><dd className="font-medium text-foreground">{credential.revocation_reason}</dd></div>}
        </dl>
      </div>

      {claims.length > 0 && (
        <div className="rounded-xl border border-border bg-card p-5">
          <h2 className="font-semibold text-foreground mb-4">Claims</h2>
          <dl className="divide-y divide-border">
            {claims.map((c) => (
              <div key={c.key} className="flex justify-between py-3">
                <dt className="text-sm text-muted-foreground">{c.label}</dt>
                <dd className="text-sm font-medium text-foreground">{c.value}</dd>
              </div>
            ))}
          </dl>
        </div>
      )}
    </div>
  );
}

