import { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { ArrowLeft, CheckCircle, XCircle } from 'lucide-react';
import { getIssuerRequest, approveRequest, rejectRequest } from '../../api/issuer';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Textarea from '../../components/common/Textarea';
import { FullPageSpinner } from '../../components/common/Spinner';
import { formatDateTime } from '../../utils/formatDate';
import toast from 'react-hot-toast';

export default function IssuerRequestDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [request, setRequest] = useState(null);
  const [loading, setLoading] = useState(true);
  const [note, setNote] = useState('');
  const [acting, setActing] = useState(false);

  useEffect(() => {
    getIssuerRequest(id)
      .then((r) => setRequest(r.data))
      .catch(() => toast.error('Failed to load request'))
      .finally(() => setLoading(false));
  }, [id]);

  const handle = async (action) => {
    setActing(true);
    try {
      if (action === 'approve') {
        await approveRequest(id, { note });
        toast.success('Request approved — credential will be issued');
      } else {
        await rejectRequest(id, { reason: note });
        toast.success('Request rejected');
      }
      navigate('/issuer/requests');
    } catch (err) {
      toast.error(err.response?.data?.detail || `Failed to ${action} request`);
    } finally { setActing(false); }
  };

  if (loading) return <FullPageSpinner />;
  if (!request) return <div className="py-16 text-center text-muted-foreground">Request not found.</div>;

  return (
    <div className="max-w-xl space-y-6">
      <Link to="/issuer/requests">
        <Button variant="ghost" size="sm"><ArrowLeft className="h-4 w-4" />Back</Button>
      </Link>

      <div className="rounded-2xl border border-border bg-card p-6 space-y-4">
        <div className="flex items-start justify-between">
          <h1 className="text-xl font-bold text-foreground">Credential Request</h1>
          <StatusBadge status={request.status} />
        </div>
        <dl className="space-y-2 text-sm">
          <div className="flex justify-between"><dt className="text-muted-foreground">Credential Type</dt><dd className="font-medium text-foreground">{request.credential_type_name || '—'}</dd></div>
          <div className="flex justify-between"><dt className="text-muted-foreground">Holder</dt><dd className="font-medium text-foreground">{request.holder_name || request.holder_email || '—'}</dd></div>
          <div className="flex justify-between"><dt className="text-muted-foreground">Requested</dt><dd className="font-medium text-foreground">{formatDateTime(request.created_at)}</dd></div>
        </dl>
        {request.message && (
          <div className="rounded-lg bg-muted/50 p-3 text-sm text-foreground">
            <p className="text-xs text-muted-foreground mb-1">Message from holder:</p>
            {request.message}
          </div>
        )}
      </div>

      {request.status === 'pending' && (
        <div className="rounded-xl border border-border bg-card p-5 space-y-4">
          <h2 className="font-semibold text-foreground">Review</h2>
          <Textarea label="Note (optional)" rows={3} value={note} onChange={(e) => setNote(e.target.value)} placeholder="Add a note for the holder..." />
          <div className="flex gap-3">
            <Button loading={acting} onClick={() => handle('approve')} className="flex-1">
              <CheckCircle className="h-4 w-4" />Approve
            </Button>
            <Button variant="outline" loading={acting} onClick={() => handle('reject')} className="flex-1 text-red-600 border-red-200 hover:bg-red-50">
              <XCircle className="h-4 w-4" />Reject
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';
import { getIssuedCredentials } from '../../api/issuer';
import { CardSkeleton } from '../../components/common/SkeletonLoader';

export default function IssuerAnalytics() {
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, active: 0, revoked: 0, expired: 0 });

  useEffect(() => {
    getIssuedCredentials({ page_size: 1000 })
      .then((r) => {
        const list = r.data?.results || r.data || [];
        const total = r.data?.count || list.length;
        const active = list.filter((c) => c.status === 'active').length;
        const revoked = list.filter((c) => c.status === 'revoked').length;
        const expired = list.filter((c) => c.status === 'expired').length;
        setStats({ total, active, revoked, expired });
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const chartData = [
    { name: 'Active', value: stats.active, fill: '#10B981' },
    { name: 'Expired', value: stats.expired, fill: '#F59E0B' },
    { name: 'Revoked', value: stats.revoked, fill: '#EF4444' },
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-foreground">Analytics</h1>
      <div className="grid sm:grid-cols-4 gap-4">
        {[
          { label: 'Total Issued', value: stats.total, color: 'text-blue-600' },
          { label: 'Active', value: stats.active, color: 'text-green-600' },
          { label: 'Expired', value: stats.expired, color: 'text-yellow-600' },
          { label: 'Revoked', value: stats.revoked, color: 'text-red-600' },
        ].map((s) => (
          <div key={s.label} className="rounded-xl border border-border bg-card p-5">
            <p className="text-sm text-muted-foreground mb-1">{s.label}</p>
            {loading ? <div className="h-8 bg-muted animate-pulse rounded" /> : (
              <p className={`text-3xl font-bold ${s.color}`}>{s.value}</p>
            )}
          </div>
        ))}
      </div>

      <div className="rounded-xl border border-border bg-card p-5">
        <h2 className="font-semibold text-foreground mb-4">Credential Status Distribution</h2>
        {loading ? <CardSkeleton /> : (
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
              <XAxis dataKey="name" tick={{ fontSize: 12, fill: 'hsl(var(--muted-foreground))' }} />
              <YAxis tick={{ fontSize: 12, fill: 'hsl(var(--muted-foreground))' }} />
