import { useEffect, useState } from 'react';
import { Bell, Check, Trash2 } from 'lucide-react';
import { getIssuerNotifications, markIssuerNotificationRead, markAllIssuerNotificationsRead, deleteIssuerNotification } from '../../api/issuer';
import { formatRelative } from '../../utils/formatDate';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

export default function IssuerNotifications() {
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getIssuerNotifications()
      .then((r) => setNotifications(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const markRead = async (id) => {
    try { await markIssuerNotificationRead(id); setNotifications((n) => n.map((x) => x.id === id ? { ...x, is_read: true } : x)); } catch { }
  };
  const markAll = async () => {
    try { await markAllIssuerNotificationsRead(); setNotifications((n) => n.map((x) => ({ ...x, is_read: true }))); toast.success('All read'); } catch { }
  };
  const remove = async (id) => {
    try { await deleteIssuerNotification(id); setNotifications((n) => n.filter((x) => x.id !== id)); } catch { }
  };

  const unread = notifications.filter((n) => !n.is_read).length;

  return (
    <div className="space-y-5 max-w-2xl">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-foreground">Notifications {unread > 0 && <span className="text-sm text-muted-foreground font-normal">({unread} unread)</span>}</h1>
        {unread > 0 && <Button size="sm" variant="outline" onClick={markAll}><Check className="h-4 w-4" />Mark all read</Button>}
      </div>
      {loading ? <p className="text-muted-foreground text-sm">Loading...</p> : notifications.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center"><Bell className="h-8 w-8 text-muted-foreground mx-auto mb-3" /><p className="text-muted-foreground text-sm">No notifications</p></div>
      ) : (
        <div className="space-y-2">
          {notifications.map((n) => (
            <div key={n.id} className={`flex items-start gap-3 rounded-xl border bg-card p-4 ${!n.is_read ? 'bg-primary/5 border-primary/20' : 'border-border'}`}>
              {!n.is_read && <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-primary" />}
              {n.is_read && <div className="mt-1.5 h-2 w-2 shrink-0" />}
              <div className="flex-1">
                <p className="text-sm font-medium text-foreground">{n.title || n.message}</p>
                <p className="text-xs text-muted-foreground mt-1">{formatRelative(n.created_at)}</p>
              </div>
              <div className="flex gap-1">
                {!n.is_read && <Button size="icon" variant="ghost" onClick={() => markRead(n.id)}><Check className="h-4 w-4 text-muted-foreground" /></Button>}
                <Button size="icon" variant="ghost" onClick={() => remove(n.id)}><Trash2 className="h-4 w-4 text-muted-foreground" /></Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useForm } from 'react-hook-form';
import { getIssuerProfile, updateIssuerProfile, getIssuerApiCredentials, regenerateIssuerApiCredentials } from '../../api/issuer';
import { changePassword } from '../../api/auth';
import Input from '../../components/common/Input';
import Textarea from '../../components/common/Textarea';
import Button from '../../components/common/Button';
import { FullPageSpinner } from '../../components/common/Spinner';
import toast from 'react-hot-toast';
import { Copy, RefreshCw } from 'lucide-react';

export default function IssuerSettings() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [apiCreds, setApiCreds] = useState(null);
  const [regenerating, setRegenerating] = useState(false);
  const [pwLoading, setPwLoading] = useState(false);
  const { register, handleSubmit, reset, formState: { errors } } = useForm();
  const { register: reg2, handleSubmit: hs2, watch, formState: { errors: e2 } } = useForm();

  useEffect(() => {
    Promise.all([getIssuerProfile(), getIssuerApiCredentials()])
      .then(([p, a]) => {
        const prof = p.data?.results?.[0] || p.data;
        setProfile(prof);
        reset({ name: prof?.organization_name, website: prof?.website, phone: prof?.phone, description: prof?.description });
        setApiCreds(a.data);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const onSave = async (data) => {
    setSaving(true);
    try { await updateIssuerProfile(data); toast.success('Profile updated'); } catch (err) { toast.error(err.response?.data?.detail || 'Save failed'); } finally { setSaving(false); }
  };

  const onPasswordChange = async (data) => {
    setPwLoading(true);
    try { await changePassword({ old_password: data.old, new_password: data.new }); toast.success('Password changed'); } catch (err) { toast.error(err.response?.data?.detail || 'Failed'); } finally { setPwLoading(false); }
  };

  const regenerateApi = async () => {
    setRegenerating(true);
    try { const r = await regenerateIssuerApiCredentials(); setApiCreds(r.data); toast.success('API credentials regenerated'); } catch { toast.error('Failed'); } finally { setRegenerating(false); }
  };

  if (loading) return <FullPageSpinner />;

  return (
    <div className="max-w-2xl space-y-8">
      <h1 className="text-2xl font-bold text-foreground">Settings</h1>

      <div className="rounded-xl border border-border bg-card p-6 space-y-4">
        <h2 className="font-semibold text-foreground">Organization Profile</h2>
        <form onSubmit={handleSubmit(onSave)} className="space-y-4">
          <Input label="Organization Name" {...register('name')} />
          <Input label="Website" type="url" {...register('website')} />
          <Input label="Phone" {...register('phone')} />
          <Textarea label="Description" rows={3} {...register('description')} />
          <Button type="submit" loading={saving}>Save Profile</Button>
        </form>
      </div>

      {apiCreds && (
        <div className="rounded-xl border border-border bg-card p-6 space-y-4">
          <h2 className="font-semibold text-foreground">API Credentials</h2>
          <div className="space-y-2">
            <div className="flex items-center justify-between rounded-lg bg-muted px-3 py-2">
              <span className="font-mono text-xs text-foreground truncate">{apiCreds.api_key || 'sk_...hidden'}</span>
              <Button size="icon" variant="ghost" onClick={() => { navigator.clipboard.writeText(apiCreds.api_key); toast.success('Copied'); }}><Copy className="h-3 w-3" /></Button>
            </div>
          </div>
          <Button size="sm" variant="outline" loading={regenerating} onClick={regenerateApi}><RefreshCw className="h-4 w-4" />Regenerate</Button>
        </div>
      )}

      <div className="rounded-xl border border-border bg-card p-6 space-y-4">
        <h2 className="font-semibold text-foreground">Change Password</h2>
        <form onSubmit={hs2(onPasswordChange)} className="space-y-4">
          <Input label="Current Password" type="password" error={e2.old?.message} {...reg2('old', { required: 'Required' })} />
          <Input label="New Password" type="password" error={e2.new?.message} {...reg2('new', { required: 'Required', minLength: { value: 8, message: 'Min 8 chars' } })} />
          <Input label="Confirm" type="password" error={e2.confirm?.message} {...reg2('confirm', { required: 'Required', validate: (v) => v === watch('new') || "Passwords don't match" })} />
          <Button type="submit" loading={pwLoading}>Update Password</Button>
        </form>
      </div>
    </div>
  );
}

