  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const debouncedSearch = useDebounce(search);

  useEffect(() => {
    setLoading(true);
    getVerificationHistory({ search: debouncedSearch, page, page_size: 20 })
      .then((r) => {
        setHistory(r.data?.results || r.data || []);
        setTotalPages(Math.ceil((r.data?.count || 1) / 20));
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [debouncedSearch, page]);

  const columns = [
    { key: 'credential_type', label: 'Credential Type', render: (v) => v || '—' },
    { key: 'holder_identifier', label: 'Holder', render: (v) => v || '—' },
    {
      key: 'is_valid',
      label: 'Result',
      render: (v) => v
        ? <span className="flex items-center gap-1 text-green-600 text-xs font-medium"><CheckCircle className="h-3 w-3" />Valid</span>
        : <span className="flex items-center gap-1 text-red-600 text-xs font-medium"><XCircle className="h-3 w-3" />Invalid</span>,
    },
    { key: 'verified_at', label: 'Date', render: (v) => formatDateTime(v || '') },
    { key: 'id', label: 'Detail', render: (v) => <Link to={`/verifier/results/${v}`} className="text-xs text-primary hover:underline">View →</Link> },
  ];

  return (
    <div className="space-y-5">
      <h1 className="text-2xl font-bold text-foreground">Verification History</h1>
      <SearchInput value={search} onChange={setSearch} placeholder="Search history..." />
      <Table columns={columns} data={history} loading={loading} emptyMessage="No verifications yet." />
      <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />
    </div>
  );
}

